using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class FileUploadController : ControllerBase
    {
        private const string UploadsDirectory = "wwwroot/uploads";

        [HttpPost("avatar")]
        public async Task<IActionResult> UploadAvatar(IFormFile file)
        {
            if (file.Length > 10485760) // 10MB max file size limit
                return BadRequest("File too large");

            var fileName = $"avatar_{Guid.NewGuid()}.{Path.GetExtension(file.FileName)}";
            var filePath = Path.Combine(UploadsDirectory, fileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            return Ok(new { filePath });
        }

        [HttpPost("document")]
        public async Task<IActionResult> UploadDocument(IFormFile file)
        {
            if (file.Length > 50000000) // 50MB max file size limit
                return BadRequest("File too large");

            var fileName = $"document_{Guid.NewGuid()}.{Path.GetExtension(file.FileName)}";
            var filePath = Path.Combine(UploadsDirectory, fileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            return Ok(new { filePath });
        }
    }
}